import type { JadePack, JadePackScores, JadeStoreCategory, PriceTier, JadeRarity } from './jadeTypes';

// Helper to generate packs
function pack(
  id: string, name: string, subtitle: string,
  category: JadeStoreCategory, rarity: JadeRarity, priceTier: PriceTier,
  priceDiamonds: number, icon: string, theme: string,
  rewards: { name: string; icon: string; rarity: JadeRarity; qty: number; guaranteed: boolean }[],
  opts: Partial<JadePack> = {}
): JadePack {
  return {
    id, name, subtitle, category, rarity, priceTier, priceDiamonds, icon,
    visualTheme: theme,
    coreRewards: rewards.map(r => ({ name: r.name, icon: r.icon, rarity: r.rarity, quantity: r.qty, guaranteed: r.guaranteed })),
    pityContribution: priceTier === 'micro' ? 1 : priceTier === 'entry' ? 2 : priceTier === 'core' ? 3 : priceTier === 'mid' ? 5 : priceTier === 'elite' ? 8 : priceTier === 'whale' ? 15 : 25,
    targetSegment: opts.targetSegment ?? 'all',
    rotationType: opts.rotationType ?? 'permanent',
    bestValue: opts.bestValue ?? false,
    mostPopular: opts.mostPopular ?? false,
    featured: opts.featured ?? false,
    isLimited: opts.isLimited ?? false,
    isNew: opts.isNew ?? false,
    seasonal: opts.seasonal,
    priceUsd: opts.priceUsd,
    purchaseLimit: opts.purchaseLimit,
    availabilityHours: opts.availabilityHours,
    bonusRewards: opts.bonusRewards,
    scores: opts.scores ?? {
      visual_desirability: 5, perceived_value: 5, real_margin: 5,
      beginner_friendliness: 5, collector_appeal: 5, whale_appeal: 5,
      urgency_strength: 5, prestige_strength: 5, retention_contribution: 5,
      overall_attractiveness: 5,
    },
    emotionalHook: opts.emotionalHook ?? '',
    adminNotes: opts.adminNotes ?? '',
  };
}

