// ── Helper functions for filtering/sorting ──
export function getPacksByCategory(category: JadeStoreCategory): JadePack[] {
  return JADE_STORE_PACKS.filter(p => p.category === category);
}

export function getFeaturedPacks(): JadePack[] {
  return JADE_STORE_PACKS.filter(p => p.featured);
}

export function getBestValuePacks(): JadePack[] {
  return JADE_STORE_PACKS.filter(p => p.bestValue);
}

export function getMostPopularPacks(): JadePack[] {
  return JADE_STORE_PACKS.filter(p => p.mostPopular);
}

export function getLimitedPacks(): JadePack[] {
  return JADE_STORE_PACKS.filter(p => p.isLimited);
}

export function sortByScore(packs: JadePack[], scoreKey: keyof JadePackScores): JadePack[] {
  return [...packs].sort((a, b) => b.scores[scoreKey] - a.scores[scoreKey]);
}
